// Node 2 — Scan the read-only vault and emit one item per Markdown file.
// Uses Node's fs/path, enabled via NODE_FUNCTION_ALLOW_BUILTIN=fs,path.
const fs = require('fs');
const path = require('path');

const ROOT = '/data/vault';
const SKIP_DIRS = new Set(['.git', '.obsidian', '.trash', 'node_modules', '.stfolder']);
const out = [];

function walk(dir) {
  let entries;
  try {
    entries = fs.readdirSync(dir, { withFileTypes: true });
  } catch (e) {
    return; // unreadable dir -> skip silently
  }
  for (const entry of entries) {
    const full = path.join(dir, entry.name);
    if (entry.isDirectory()) {
      if (SKIP_DIRS.has(entry.name)) continue;
      walk(full);
    } else if (entry.isFile() && entry.name.toLowerCase().endsWith('.md')) {
      try {
        out.push({ json: { file: path.relative(ROOT, full), raw: fs.readFileSync(full, 'utf8') } });
      } catch (e) { /* skip unreadable file */ }
    }
  }
}

walk(ROOT);

if (out.length === 0) {
  throw new Error('No Markdown files under /data/vault. Check VAULT_PATH in .env and that the drive is shared in Docker Desktop > Settings > Resources > File Sharing.');
}
return out;

// Node 3 — Parse flat YAML frontmatter, keep STALE active projects, rank them,
// and build the cloud-LLM request. Returns [] (no items) when nothing is stale,
// so nodes 4 and 5 never run and no message is sent.
const items = $input.all();
const GLOBAL_STALE_DAYS = 5;

// Local-midnight "today" so day math never drifts across timezones.
const now = new Date();
const today = new Date(now.getFullYear(), now.getMonth(), now.getDate());

function parseLocalDate(s) {
  const m = String(s).trim().match(/^(\d{4})-(\d{2})-(\d{2})/);
  if (!m) return null;
  return new Date(Number(m[1]), Number(m[2]) - 1, Number(m[3]));
}
const daysBetween = (a, b) => Math.round((a - b) / 86400000);

function parseFrontmatter(text) {
  const m = text.match(/^﻿?---\s*\r?\n([\s\S]*?)\r?\n---/);
  if (!m) return {};
  const fm = {};
  for (const line of m[1].split(/\r?\n/)) {
    const t = line.trim();
    if (!t || t.startsWith('#')) continue;
    const idx = line.indexOf(':');
    if (idx === -1) continue;
    const key = line.slice(0, idx).trim();
    let val = line.slice(idx + 1).trim();
    val = val.replace(/\s+#.*$/, '');          // strip trailing inline comment
    val = val.replace(/^["']|["']$/g, '');      // strip surrounding quotes
    if (val.startsWith('[') && val.endsWith(']')) {
      val = val.slice(1, -1).split(',').map(s => s.trim().replace(/^["']|["']$/g, '')).filter(Boolean);
    }
    fm[key] = val;
  }
  return fm;
}

function bodyOf(text) {
  const m = text.match(/^﻿?---\s*\r?\n[\s\S]*?\r?\n---\s*\r?\n?/);
  return m ? text.slice(m[0].length) : text;
}

const stale = [];
for (const item of items) {
  const text = item.json.raw;
  if (typeof text !== 'string') continue;
  const fm = parseFrontmatter(text);
  if (String(fm.type || '').toLowerCase() !== 'project') continue;   // projects only
  const status = String(fm.status || '').toLowerCase();
  if (status === 'done') continue;                                   // ignore finished
  const last = parseLocalDate(fm.last_actionable_date);
  if (!last) continue;
  const threshold = parseInt(fm.stale_after_days, 10) || GLOBAL_STALE_DAYS;
  const daysStale = daysBetween(today, last);
  if (daysStale < threshold) continue;                               // still warm

  const recent = bodyOf(text)
    .split(/\r?\n/)
    .map(l => l.trim())
    .filter(l => /^- |^\* |^\d+\.|\[ \]|\bnext\b|\blog\b|\d{4}-\d{2}-\d{2}/i.test(l))
    .slice(-8)
    .join('\n');

  stale.push({
    title: fm.title || String(item.json.file || 'untitled').replace(/\.md$/i, ''),
    status,
    priority: String(fm.priority || 'medium').toLowerCase(),
    deadline: fm.deadline || '',
    last_actionable_date: fm.last_actionable_date,
    days_stale: daysStale,
    recent_notes: recent,
  });
}

if (stale.length === 0) return [];   // nothing cold -> pipeline ends quietly

// Rank: nearest deadline first, then priority, then most days_stale.
const prRank = { high: 0, medium: 1, low: 2 };
stale.sort((a, b) => {
  const ad = a.deadline ? parseLocalDate(a.deadline) : null;
  const bd = b.deadline ? parseLocalDate(b.deadline) : null;
  if (ad && bd && +ad !== +bd) return ad - bd;
  if (ad && !bd) return -1;
  if (!ad && bd) return 1;
  const pr = (prRank[a.priority] ?? 1) - (prRank[b.priority] ?? 1);
  if (pr !== 0) return pr;
  return b.days_stale - a.days_stale;
});

const SYSTEM_PROMPT = `You are the user's Agentic Second Brain - a terse, perceptive chief-of-staff that resurfaces neglected projects each morning over WhatsApp.
You receive JSON: today's date and an array of STALE projects (each with title, status, priority, deadline, days_stale, recent_notes). The array is PRE-SORTED by leverage (most important first).

RULES:
1. Nudge the FIRST project in the array. You may add at most ONE short secondary line referencing the second project if it is also urgent.
2. Output ONLY the WhatsApp message body. No preamble, no sign-off, no markdown code fences, no JSON.
3. Format STRICTLY for a narrow phone screen using WhatsApp formatting: *bold* with single asterisks, _italics_ with underscores, leading emojis as bullets. Keep it under ~90 words. Short lines. One blank line between each of the three blocks.
4. Follow this EXACT 3-step flow, each on its own labelled line:
   *HOOK* - name what went cold and for how many days (use days_stale).
   *CONTEXT* - paraphrase recent_notes so they instantly recognise where they left off.
   *MICRO-ACTION* - ONE concrete task doable in 10 minutes. Absurdly low-friction.
   Prefix each block label with a relevant emoji.
5. Tone: warm, direct, zero guilt-tripping. Never invent facts that are not present in the notes. If recent_notes is empty, say the thread went quiet and suggest re-reading the note as the micro-action.`;
const user = JSON.stringify({ today: today.toISOString().slice(0, 10), stale_projects: stale }, null, 2);
return [{ json: { system: SYSTEM_PROMPT, user, count: stale.length } }];
